    "content": "/* ============================================================\n   Medical Education Platform — global styles\n   - RTL ready, Persian font (Vazirmatn / IBM Plex Sans Arabic)\n   - Dark mode via .dark on <html>\n   - CSS variables for user-customizable font size/family\n   ============================================================ */\n\n:root {\n  --app-font-size: 16px;\n  --app-font-family: 'Vazirmatn', system-ui, sans-serif;\n  --app-line-height: 1.7;\n}\n\n* { box-sizing: border-box; }\nhtml { scroll-behavior: smooth; }\nbody {\n  font-family: var(--app-font-family);\n  font-size: var(--app-font-size);\n  line-height: var(--app-line-height);\n  -webkit-font-smoothing: antialiased;\n  transition: font-size 0.2s, font-family 0.2s, line-height 0.2s;\n}\n\n/* scrollbar */\n::-webkit-scrollbar { width: 10px; height: 10px; }\n::-webkit-scrollbar-track { background: transparent; }\n::-webkit-scrollbar-thumb { background: rgba(100,116,139,0.3); border-radius: 5px; }\n::-webkit-scrollbar-thumb:hover { background: rgba(100,116,139,0.5); }\n\n/* utility */\n.fade-in { animation: fadeIn 0.3s ease-out; }\n.slide-up { animation: slideUp 0.3s ease-out; }\n.scale-in { animation: scaleIn 0.2s ease-out; }\n\n@keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }\n@keyframes slideUp { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }\n@keyframes scaleIn { from { opacity: 0; transform: scale(0.95); } to { opacity: 1; transform: scale(1); } }\n\n/* line-clamp helpers (fallback if Tailwind plugin not loaded) */\n.line-clamp-1 { display: -webkit-box; -webkit-line-clamp: 1; -webkit-box-orient: vertical; overflow: hidden; }\n.line-clamp-2 { display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden; }\n.line-clamp-3 { display: -webkit-box; -webkit-line-clamp: 3; -webkit-box-orient: vertical; overflow: hidden; }\n\n/* markdown preview styles for editor */\n.markdown-preview { font-size: var(--app-font-size); line-height: var(--app-line-height); }\n.markdown-preview h1 { font-size: 2em; font-weight: 700; margin: 0.67em 0; border-bottom: 2px solid #e2e8f0; padding-bottom: 0.3em; }\n.markdown-preview h2 { font-size: 1.5em; font-weight: 700; margin: 0.83em 0; border-bottom: 1px solid #e2e8f0; padding-bottom: 0.3em; }\n.markdown-preview h3 { font-size: 1.25em; font-weight: 600; margin: 1em 0; }\n.markdown-preview h4 { font-size: 1em; font-weight: 600; margin: 1em 0; }\n.markdown-preview p { margin: 0.75em 0; line-height: 1.8; }\n.markdown-preview ul, .markdown-preview ol { padding-right: 1.5em; margin: 0.75em 0; }\n.markdown-preview ul { list-style: disc; }\n.markdown-preview ol { list-style: decimal; }\n.markdown-preview li { margin: 0.25em 0; }\n.markdown-preview a { color: #2563eb; text-decoration: underline; }\n.markdown-preview blockquote { border-right: 4px solid #3b82f6; padding: 0.5em 1em; margin: 1em 0; background: #eff6ff; color: #475569; border-radius: 6px; }\n.markdown-preview code { background: #f1f5f9; padding: 0.15em 0.4em; border-radius: 4px; font-size: 0.9em; font-family: 'Vazirmatn', monospace; }\n.markdown-preview pre { background: #1e293b; color: #e2e8f0; padding: 1em; border-radius: 8px; overflow-x: auto; margin: 1em 0; }\n.markdown-preview pre code { background: transparent; padding: 0; color: inherit; }\n.markdown-preview table { width: 100%; border-collapse: collapse; margin: 1em 0; }\n.markdown-preview th, .markdown-preview td { border: 1px solid #e2e8f0; padding: 0.5em 0.75em; text-align: right; }\n.markdown-preview th { background: #f8fafc; font-weight: 600; }\n.markdown-preview img { max-width: 100%; border-radius: 8px; margin: 1em 0; }\n.markdown-preview hr { border: 0; border-top: 2px solid #e2e8f0; margin: 2em 0; }\n\n/* EasyMDE customizations for RTL */\n.EasyMDEContainer { direction: rtl; }\n.EasyMDEContainer .editor-toolbar { border-radius: 12px 12px 0 0; border-color: #e2e8f0; background: #f8fafc; }\n.EasyMDEContainer .CodeMirror { border-radius: 0 0 12px 12px; border-color: #e2e8f0; direction: rtl; font-family: 'Vazirmatn', monospace; padding: 8px; font-size: 15px; }\n.EasyMDEContainer .editor-preview { direction: rtl; padding: 16px; font-family: var(--app-font-family); }\n.EasyMDEContainer .editor-preview-side { direction: rtl; }\n\n/* flashcard flip animation */\n.flip-card { perspective: 1000px; }\n.flip-card-inner { transition: transform 0.5s; transform-style: preserve-3d; position: relative; }\n.flip-card.flipped .flip-card-inner { transform: rotateY(180deg); }\n.flip-card-front, .flip-card-back { backface-visibility: hidden; -webkit-backface-visibility: hidden; }\n.flip-card-back { position: absolute; top: 0; left: 0; width: 100%; height: 100%; transform: rotateY(180deg); }\n\n/* toast */\n.toast-container { position: fixed; bottom: 20px; left: 50%; transform: translateX(-50%); z-index: 9999; display: flex; flex-direction: column; gap: 8px; }\n.toast { padding: 12px 20px; border-radius: 10px; color: white; font-size: 14px; box-shadow: 0 10px 30px rgba(0,0,0,0.15); animation: slideUp 0.3s; max-width: 400px; }\n.toast-success { background: #10b981; }\n.toast-error { background: #ef4444; }\n.toast-info { background: #3b82f6; }\n.toast-warning { background: #f59e0b; }\n\n/* loader */\n.loader {\n  width: 20px; height: 20px;\n  border: 2px solid rgba(255,255,255,0.3);\n  border-top-color: white;\n  border-radius: 50%;\n  animation: spin 0.6s linear infinite;\n  display: inline-block;\n}\n@keyframes spin { to { transform: rotate(360deg); } }\n\n/* sidebar transition */\n.sidebar-link { transition: all 0.2s; }\n.sidebar-link.active { background: linear-gradient(135deg, #3b82f6, #06b6d4); color: white; box-shadow: 0 4px 12px rgba(59,130,246,0.3); }\n\n/* ============================================================\n   موبایل: سایدبار در سمت راست (RTL) قرار داره\n   برای مخفی کردن باید translateX(100%) باشه (مثبت = به راست)\n   ============================================================ */\n.sidebar { transition: transform 0.3s ease; }\n.sidebar-overlay { transition: opacity 0.3s; opacity: 0; pointer-events: none; }\n.sidebar-overlay.show { opacity: 1; pointer-events: auto; }\n\n@media (max-width: 768px) {\n  /* سایدبار در موبایل مخفی (translateX مثبت = به راست، چون سایدبار راست‌چین است) */\n  .sidebar { transform: translateX(100%); }\n  .sidebar.open { transform: translateX(0); }\n  .main-content { margin-right: 0 !important; margin-left: 0 !important; }\n  .mobile-menu-btn { display: flex !important; }\n  .sidebar-overlay { display: block; }\n}\n\n@media (min-width: 769px) {\n  .mobile-menu-btn { display: none !important; }\n  .sidebar-overlay { display: none !important; }\n}\n\n/* dark mode tweaks */\n.dark .markdown-preview blockquote { background: #1e293b; color: #cbd5e1; }\n.dark .markdown-preview code { background: #334155; }\n.dark .markdown-preview th { background: #1e293b; }\n\n/* font button (in header) */\n.font-settings-btn {\n  position: fixed;\n  bottom: 20px;\n  left: 20px;\n  z-index: 40;\n  width: 48px;\n  height: 48px;\n  border-radius: 50%;\n  background: linear-gradient(135deg, #3b82f6, #06b6d4);\n  color: white;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  box-shadow: 0 4px 16px rgba(59, 130, 246, 0.4);\n  cursor: pointer;\n  border: none;\n  transition: transform 0.2s;\n}\n.font-settings-btn:hover { transform: scale(1.1); }\n\n/* mobile responsive tweaks */\n@media (max-width: 640px) {\n  .stat-card-grid { grid-template-columns: repeat(2, 1fr) !important; }\n  .page-padding { padding: 1rem !important; }\n  .modal-mobile-full { width: 100% !important; max-width: 100% !important; height: 100% !important; max-height: 100% !important; border-radius: 0 !important; }\n  \n  /* Improve AI page responsiveness */\n  .grid-cols-1.md\\:grid-cols-2 { grid-template-columns: 1fr !important; }\n}\n\n.topic-card-container {\n  margin-bottom: 1.5rem;\n  width: 100%;\n}\n",
